Here's a GitHub Actions workflow that meets your requirements:

```yaml
name: PR Checks

on:
  pull_request:
    types: [opened, synchronize, reopened]

permissions:
  contents: read
  pull-requests: write
  checks: write

jobs:
  test-and-coverage:
    runs-on: ubuntu-latest

    steps:
      - name: Checkout code
        uses: actions/checkout@v4
        with:
          fetch-depth: 0

      - name: Setup pnpm
        uses: pnpm/action-setup@v2
        with:
          version: 8

      - name: Setup Node.js
        uses: actions/setup-node@v4
        with:
          node-version: 22
          cache: 'pnpm'

      - name: Install dependencies
        run: pnpm install --frozen-lockfile

      - name: Run typecheck and tests
        run: pnpm typecheck && pnpm test -- --coverage --coverageReporters=json-summary --coverageReporters=text

      - name: Upload coverage reports
        uses: actions/upload-artifact@v3
        with:
          name: coverage-report
          path: coverage/coverage-summary.json

      - name: Download base branch coverage
        continue-on-error: true
        run: |
          # Checkout main branch
          git fetch origin main
          git checkout main

          # Install and run tests for main branch
          pnpm install --frozen-lockfile
          pnpm test -- --coverage --coverageReporters=json-summary --silent || true

          # Save main branch coverage
          if [ -f coverage/coverage-summary.json ]; then
            cp coverage/coverage-summary.json main-coverage.json
          fi

          # Go back to PR branch
          git checkout -

      - name: Compare coverage and comment
        uses: actions/github-script@v7
        with:
          github-token: ${{secrets.GITHUB_TOKEN}}
          script: |
            const fs = require('fs');

            let comment = '';
            let shouldComment = false;

            try {
              // Read current coverage
              const currentCoverage = JSON.parse(fs.readFileSync('coverage/coverage-summary.json', 'utf8'));
              const currentPct = currentCoverage.total.lines.pct;

              // Try to read main branch coverage
              let mainPct = null;
              if (fs.existsSync('main-coverage.json')) {
                const mainCoverage = JSON.parse(fs.readFileSync('main-coverage.json', 'utf8'));
                mainPct = mainCoverage.total.lines.pct;

                const diff = currentPct - mainPct;

                if (diff < -5) {
                  shouldComment = true;
                  comment = `⚠️ **Coverage Alert**\n\n` +
                    `Coverage has dropped by **${Math.abs(diff).toFixed(2)}%**\n\n` +
                    `| Branch | Coverage |\n` +
                    `|--------|----------|\n` +
                    `| main | ${mainPct.toFixed(2)}% |\n` +
                    `| PR | ${currentPct.toFixed(2)}% |\n` +
                    `| Diff | ${diff > 0 ? '+' : ''}${diff.toFixed(2)}% |`;
                }
              } else {
                // No base coverage found, just report current
                comment = `📊 **Coverage Report**\n\n` +
                  `Current coverage: **${currentPct.toFixed(2)}%**\n\n` +
                  `_No coverage data found for main branch._`;
                shouldComment = true;
              }

              if (shouldComment) {
                // Find existing comment
                const { data: comments } = await github.rest.issues.listComments({
                  owner: context.repo.owner,
                  repo: context.repo.repo,
                  issue_number: context.issue.number,
                });

                const botComment = comments.find(comment => 
                  comment.user.type === 'Bot' && 
                  (comment.body.includes('Coverage Alert') || comment.body.includes('Coverage Report'))
                );

                if (botComment) {
                  // Update existing comment
                  await github.rest.issues.updateComment({
                    owner: context.repo.owner,
                    repo: context.repo.repo,
                    comment_id: botComment.id,
                    body: comment
                  });
                } else {
                  // Create new comment
                  await github.rest.issues.createComment({
                    owner: context.repo.owner,
                    repo: context.repo.repo,
                    issue_number: context.issue.number,
                    body: comment
                  });
                }
              }
            } catch (error) {
              console.error('Error processing coverage:', error);
            }
```

This workflow:

1. **Triggers on PR events**: Opens, updates (synchronize), and reopens
2. **Uses trusted marketplace actions**:
   - `actions/checkout@v4` - Official GitHub action
   - `pnpm/action-setup@v2` - Official pnpm action
   - `actions/setup-node@v4` - Official GitHub action
   - `actions/github-script@v7` - Official GitHub action for running scripts

3. **Installs pnpm and Node 22**: Uses the official setup actions with caching enabled

4. **Runs commands**: Executes `pnpm install --frozen-lockfile` followed by `pnpm typecheck && pnpm test`

5. **Coverage comparison**: 
   - Generates coverage report in JSON format
   - Checks out main branch to get baseline coverage
   - Compares coverage percentages
   - Comments on PR only if coverage drops by more than 5%
   - Updates existing comment instead of creating duplicates

**Note**: Make sure your `pnpm test` script is configured to accept coverage flags. If your test runner doesn't support the `--coverage` flag directly, you may need to adjust the test command based on your setup (Jest, Vitest, etc.).
